import{y as e,w as r,x as n}from"./chunks/theme.BubYwfvn.js";import{u as a}from"./chunks/links.AjectzQB.js";import{o as l,c as s,ah as o}from"./chunks/framework.DKbJLo0O.js";const y=JSON.parse('{"title":"Pointeract","description":"Pointeract 是一个前端库，用于解析用户交互并派发平移缩放事件，是 Hammer.js 的轻量级且可扩展的替代方案。","frontmatter":{"layout":"project","title":"Pointeract","description":"Pointeract 是一个前端库，用于解析用户交互并派发平移缩放事件，是 Hammer.js 的轻量级且可扩展的替代方案。","logo":"https://pointeract.consensia.cc/logo.svg"},"headers":[],"relativePath":"zh-Hans/projects/pointeract.md","filePath":"zh-Hans/projects/pointeract.md","lastUpdated":1775407704000}'),i={name:"zh-Hans/projects/pointeract.md"},x=Object.assign(i,{setup(c){return a([{name:"文档",url:"https://www.npmjs.com/package/pointeract  ",icon:e,color:"#425aef"},{name:"GitHub",url:"https://github.com/hesprs/pointeract  ",icon:r,color:"#010409"},{name:"npm",url:"https://www.npmjs.com/package/pointeract  ",icon:n,color:"#EA2039"}]),(d,t)=>(l(),s("div",null,[...t[0]||(t[0]=[o('<h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to “简介”">​</a></h2><p>Pointeract 是一个轻量级的 JavaScript/TypeScript 工具库，专注于一件事——处理 DOM 元素的用户交互，例如多点触控和触控板操作。</p><p>借助 TypeScript 独特而灵活的类型系统及其动态特性，Pointeract 实现了高度<strong>模块化、可扩展且高效</strong>的架构。其核心包体积仅 <strong>1KB</strong>（压缩后），功能则由同样小巧的模块提供。它完全支持 <strong>摇树优化（tree-shaking）</strong>，使用的模块越少，最终打包体积就越小。</p><p>主页与文档：<a href="https://pointeract.consensia.cc" target="_blank" rel="noreferrer">pointeract.consensia.cc</a>。</p><h2 id="支持的功能" tabindex="-1">支持的功能 <a class="header-anchor" href="#支持的功能" aria-label="Permalink to “支持的功能”">​</a></h2><ul><li><strong>点击</strong>（双击、三击、四击、任意次数点击）</li><li><strong>拖拽</strong></li><li><strong>滑动（全方向，单指/多指）</strong></li><li><strong>滚轮与触摸板支持的平移与缩放</strong>（支持 <code>Ctrl</code>/<code>Shift</code> 键绑定）</li><li><strong>多指触控支持的平移与缩放</strong>（平移、捏合）</li><li><strong>一键式默认行为阻止</strong></li><li><strong>全交互平滑处理</strong>（包括拖拽、平移、缩放及任何涉及数值变化的交互）</li></ul><p>这些交互功能均以模块化形式提供，可灵活组合，从简单的拖放操作到复杂的画布应用皆能胜任。</p><p>若缺少您所需的功能？<a href="https://pointeract.consensia.cc/development/custom-modules" target="_blank" rel="noreferrer">请编写您的自定义模块</a>！</p><h2 id="优势" tabindex="-1">优势 <a class="header-anchor" href="#优势" aria-label="Permalink to “优势”">​</a></h2><ul><li><strong>🐣 超小体积</strong>：核心仅 <strong>1KB</strong>（压缩后），常规使用约 <strong>1-2KB</strong>。</li><li><strong>💪 强大稳健</strong>：在复杂手势处理上表现出色，而大多数交互库在此类场景下会失败，<a href="https://pointeract.consensia.cc/development/testing#monkey-test" target="_blank" rel="noreferrer">原因何在？</a></li><li><strong>🧩 高度可扩展</strong>：可通过模块 API 轻松扩展 Pointeract 功能。</li><li><strong>🔌 运行时灵活</strong>：配置项可响应式更新，可在运行时随时停止或启动任意模块。</li><li><strong>🛡️ 安全可靠</strong>：不直接修改 DOM（<code>PreventDefault</code> 模块除外），细致的清理机制可防止内存泄漏。</li></ul><h2 id="pointeract-如何脱颖而出" tabindex="-1">Pointeract 如何脱颖而出？ <a class="header-anchor" href="#pointeract-如何脱颖而出" aria-label="Permalink to “Pointeract 如何脱颖而出？”">​</a></h2><p>市面上已有众多交互库，其中最著名的包括 <code>d3-drag</code> + <code>d3-zoom</code>、<code>Interact.js</code> 和 <code>Hammer.js</code>，但 Pointeract 却与众不同。</p><table tabindex="0"><thead><tr><th style="text-align:left;">标准</th><th style="text-align:center;">Pointeract</th><th style="text-align:center;">D3 Drag + D3 Zoom</th><th style="text-align:center;">Hammer.js</th><th style="text-align:center;">Interact.js</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>使用 TypeScript 编写？</strong></td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td></tr><tr><td style="text-align:left;"><strong>支持摇树优化 (Tree-shakeable)？</strong></td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td style="text-align:left;"><strong>总包大小 (压缩后)</strong></td><td style="text-align:center;">👑 <a href="https://bundlejs.com/?q=pointeract%40latest" target="_blank" rel="noreferrer">2.7KB</a></td><td style="text-align:center;"><a href="https://bundlejs.com/?q=d3-drag%403.0.0%2Cd3-zoom%403.0.0" target="_blank" rel="noreferrer">17KB</a></td><td style="text-align:center;"><a href="https://bundlejs.com/?q=hammerjs%402.0.8" target="_blank" rel="noreferrer">7KB</a></td><td style="text-align:center;"><a href="https://bundlejs.com/?q=interactjs%401.10.27" target="_blank" rel="noreferrer">28KB</a></td></tr><tr><td style="text-align:left;"><strong>最后更新时间</strong></td><td style="text-align:center;">👑 活跃维护中</td><td style="text-align:center;">2021</td><td style="text-align:center;">2015</td><td style="text-align:center;">2023</td></tr><tr><td style="text-align:left;"><strong>多功能性</strong></td><td style="text-align:center;">指针与滚轮操作 + 部分工具</td><td style="text-align:center;">👑 指针与滚轮操作 + 生态系统</td><td style="text-align:center;">仅限指针相关</td><td style="text-align:center;">指针相关 + 全面工具集</td></tr><tr><td style="text-align:left;"><strong>支持的设备</strong></td><td style="text-align:center;">👑 鼠标、滚轮、触控、触摸板</td><td style="text-align:center;">⚠️ 不支持触摸板</td><td style="text-align:center;">⚠️ 不支持触摸板或鼠标滚轮</td><td style="text-align:center;">⚠️ 不支持触摸板或鼠标滚轮</td></tr><tr><td style="text-align:left;"><strong>稳健性 (通过 <a href="https://pointeract.consensia.cc/development/testing#monkey-test" target="_blank" rel="noreferrer">猴子测试</a>)</strong></td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌ 元素抖动</td><td style="text-align:center;">❌ 忽略第二次触摸</td></tr><tr><td style="text-align:left;"><strong>可扩展性？</strong></td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr></tbody></table><h2 id="许可证" tabindex="-1">许可证 <a class="header-anchor" href="#许可证" aria-label="Permalink to “许可证”">​</a></h2><p>Pointeract 采用 <a href="https://www.apache.org/licenses/LICENSE-2.0.html" target="_blank" rel="noreferrer">Apache License 2.0</a> 授权。</p>',15)])]))}});export{y as __pageData,x as default};
